local SEED = os.time()
math.randomseed(SEED)

function generateToken()
    local token = ""
    for i=1, 32 do
        token = token .. string.char(math.random(97,122)) -- lowercase alphabet
        token = token .. string.char(math.random(65,90)) -- uppercase alphabet
        token = token .. tostring(math.random(10)) -- numbers
    end
    return token:sub(1, 32) -- ensure length is 32 characters
end

function generateNonce()
    local nonce = math.random(1000000000, 9999999999)
    return tostring(nonce)
end